import React, { useEffect, useState } from "react";
import {
  Button,
  Typography,
  Box,
  Alert,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { getRiderStatus } from "../../services/api";

export default function RiderDashboard() {
  const navigate = useNavigate();
  const [rider, setRider] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const token = localStorage.getItem("token");
    console.log("📌 Token from localStorage:", token);

    if (!token) {
      navigate("/login");
      return;
    }

    getRiderStatus(token)
      .then((res) => {
        console.log("📌 Rider status response:", res.data);
        setRider(res.data.user);
        setLoading(false);
      })
      .catch((err) => {
        console.error("❌ Error loading rider data:", err.response?.data || err.message);
        setError(err.response?.data?.message || "Error loading rider data");
        setLoading(false);
      });
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("role");
    navigate("/login");
  };

  if (loading) {
    return (
      <Box sx={{ p: 4, textAlign: "center" }}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Box sx={{ p: 4 }}>
        <Alert severity="error">{error}</Alert>
        <Button
          sx={{ mt: 2 }}
          variant="contained"
          color="primary"
          onClick={handleLogout}
        >
          Back to Login
        </Button>
      </Box>
    );
  }

  if (!rider) {
    return (
      <Box sx={{ p: 4 }}>
        <Alert severity="warning">No rider data available.</Alert>
      </Box>
    );
  }

  // 🚨 If rider has not uploaded documents yet → redirect to upload page
  if (!rider.documents || !rider.documents.license) {
    navigate("/upload-docs");
    return null;
  }

  // 🚨 If documents uploaded but waiting for approval
  if (rider.approvalStatus === "pending") {
    return (
      <Box sx={{ p: 4 }}>
        <Typography variant="h5" sx={{ mb: 2 }}>
          Account Pending Approval
        </Typography>
        <Typography sx={{ mb: 2 }}>
          Your documents are under review. Please wait for admin approval.
        </Typography>
        <Button
          variant="contained"
          sx={{ bgcolor: "black", color: "white" }}
          onClick={handleLogout}
        >
          Logout
        </Button>
      </Box>
    );
  }

  // 🚨 If approved → show dashboard
  return (
    <Box sx={{ p: 4 }}>
      <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
        Rider Dashboard
      </Typography>
      <Typography variant="body1" sx={{ mb: 3 }}>
        Welcome {rider.fullName}! 🛵 You can see ride requests, track trips, and manage earnings.
      </Typography>

      <Button
        variant="contained"
        sx={{ bgcolor: "black", color: "white" }}
        onClick={handleLogout}
      >
        Logout
      </Button>
    </Box>
  );
}
